import React, { useEffect, useState } from 'react';
import './Dashboard.css';

const API_URL = 'http://localhost:5000/api';

const Dashboard = ({ userRole, onNavigate }) => {
  const [stats, setStats] = useState({
    totalPatients: 0,
    totalDoctors: 0,
    totalAppointments: 0,
    confirmedAppointments: 0,
  });

  const [appointments, setAppointments] = useState([]);
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Fetch statistics
  useEffect(() => {
    fetchStatistics();
  }, []);

  const fetchStatistics = async () => {
    try {
      setLoading(true);
      setError('');

      const response = await fetch(`${API_URL}/dashboard/statistics`);
      const result = await response.json();

      if (result.success) {
        setStats({
          totalPatients: result.data.totalPatients,
          totalDoctors: result.data.totalDoctors,
          totalAppointments: result.data.totalAppointments,
          confirmedAppointments: result.data.confirmedAppointments,
        });
        setAppointments(result.data.recentAppointments || []);
        setPatients(result.data.recentPatients || []);
      } else {
        setError(result.error || 'Failed to load statistics');
      }
    } catch (err) {
      console.error('Error fetching statistics:', err);
      setError('Unable to connect to server. Please make sure the backend is running.');
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status) => {
    const colors = {
      'Confirmed': '#4caf50',
      'Pending': '#ff9800',
      'Completed': '#4a90e2',
      'Cancelled': '#f44336',
      'Active': '#4caf50',
    };
    return colors[status] || '#999';
  };

  if (loading && stats.totalPatients === 0) {
    return (
      <div className="dashboard loading-state">
        <div className="loading-spinner">
          <div className="spinner"></div>
          <p>Loading dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Welcome, {userRole === 'admin' ? 'Administrator' : 'Healthcare Professional'}</h1>
        <p className="date-time">{new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
      </div>

      {error && (
        <div className="error-message">
          <span>⚠️</span>
          <p>{error}</p>
          <button onClick={fetchStatistics} className="retry-btn">Retry</button>
        </div>
      )}

      {/* Stats Cards */}
      <div className="stats-container">
        <div className="stat-card">
          <div className="stat-icon">👥</div>
          <div className="stat-content">
            <h3>Total Patients</h3>
            <p className="stat-value">{stats.totalPatients}</p>
            <span className="stat-change">Total registered</span>
          </div>
          <div className="stat-bar">
            <div className="stat-fill" style={{ width: `${Math.min(stats.totalPatients * 5, 100)}%` }}></div>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon">👨‍⚕️</div>
          <div className="stat-content">
            <h3>Active Doctors</h3>
            <p className="stat-value">{stats.totalDoctors}</p>
            <span className="stat-change">Total doctors</span>
          </div>
          <div className="stat-bar">
            <div className="stat-fill" style={{ width: `${Math.min(stats.totalDoctors * 10, 100)}%` }}></div>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon">📅</div>
          <div className="stat-content">
            <h3>Total Appointments</h3>
            <p className="stat-value">{stats.totalAppointments}</p>
            <span className="stat-change">{stats.confirmedAppointments} confirmed</span>
          </div>
          <div className="stat-bar">
            <div className="stat-fill" style={{ width: `${Math.min((stats.confirmedAppointments / Math.max(stats.totalAppointments, 1)) * 100, 100)}%` }}></div>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon">✓</div>
          <div className="stat-content">
            <h3>Appointment Rate</h3>
            <p className="stat-value">{stats.totalAppointments > 0 ? Math.round((stats.confirmedAppointments / stats.totalAppointments) * 100) : 0}%</p>
            <span className="stat-change">Confirmed rate</span>
          </div>
          <div className="stat-bar">
            <div className="stat-fill" style={{ width: `${stats.totalAppointments > 0 ? Math.round((stats.confirmedAppointments / stats.totalAppointments) * 100) : 0}%` }}></div>
          </div>
        </div>
      </div>

      {/* Main Content Grid */}
      <div className="dashboard-grid">
        {/* Recent Appointments */}
        <div className="card">
          <div className="card-header">
            <h2>📅 Recent Appointments</h2>
            <button className="btn-link" onClick={() => onNavigate('appointments')}>View All</button>
          </div>
          {appointments.length === 0 ? (
            <div className="empty-state">
              <p>No appointments yet</p>
              <button className="btn-add-small" onClick={() => onNavigate('appointments')}>Book Now</button>
            </div>
          ) : (
            <div className="appointment-list">
              {appointments.map((apt) => (
                <div key={apt.id} className="appointment-item">
                  <div className="apt-time">
                    <span className="apt-clock">🕐</span>
                    <span className="apt-hour">{apt.appointmentTime}</span>
                  </div>
                  <div className="apt-details">
                    <p className="apt-patient">{apt.patientName}</p>
                    <p className="apt-doctor">Dr. {apt.doctorName}</p>
                  </div>
                  <span className="apt-badge" style={{ backgroundColor: getStatusColor(apt.status) }}>
                    {apt.status}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recent Patients */}
        <div className="card">
          <div className="card-header">
            <h2>👥 Recent Patients</h2>
            <button className="btn-link" onClick={() => onNavigate('patient-registration')}>Add New</button>
          </div>
          {patients.length === 0 ? (
            <div className="empty-state">
              <p>No patients registered yet</p>
              <button className="btn-add-small" onClick={() => onNavigate('patient-registration')}>Register Now</button>
            </div>
          ) : (
            <div className="patient-list">
              {patients.map((patient) => (
                <div key={patient.id} className="patient-item">
                  <div className="patient-avatar">
                    {patient.firstName.charAt(0)}
                  </div>
                  <div className="patient-info">
                    <p className="patient-name">{patient.firstName} {patient.lastName}</p>
                    <p className="patient-date">{new Date(patient.registeredAt).toLocaleDateString()}</p>
                  </div>
                  <span className="patient-status" style={{ backgroundColor: getStatusColor(patient.status) }}>
                    {patient.status}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Actions */}
        <div className="card quick-actions">
          <div className="card-header">
            <h2>⚡ Quick Actions</h2>
          </div>
          <div className="action-buttons">
            <button className="action-btn" onClick={() => onNavigate('patient-registration')}>
              <span className="action-icon">➕</span>
              <span>Register Patient</span>
            </button>
            <button className="action-btn" onClick={() => onNavigate('add-doctor')}>
              <span className="action-icon">👨‍⚕️</span>
              <span>Add Doctor</span>
            </button>
            <button className="action-btn" onClick={() => onNavigate('appointments')}>
              <span className="action-icon">📅</span>
              <span>Book Appointment</span>
            </button>
            <button className="action-btn" onClick={() => onNavigate('patients-list')}>
              <span className="action-icon">📋</span>
              <span>View Patients</span>
            </button>
          </div>
        </div>

        {/* System Status */}
        <div className="card system-status">
          <div className="card-header">
            <h2>🔧 System Status</h2>
          </div>
          <div className="status-items">
            <div className="status-item">
              <span className="status-label">API Server</span>
              <span className="status-indicator online">●</span>
              <span className="status-text">Connected</span>
            </div>
            <div className="status-item">
              <span className="status-label">Database</span>
              <span className="status-indicator online">●</span>
              <span className="status-text">Active</span>
            </div>
            <div className="status-item">
              <span className="status-label">Total Records</span>
              <span className="status-indicator online">●</span>
              <span className="status-text">{stats.totalPatients + stats.totalDoctors + stats.totalAppointments} items</span>
            </div>
            <div className="status-item">
              <span className="status-label">Last Updated</span>
              <span className="status-indicator online">●</span>
              <span className="status-text">{new Date().toLocaleTimeString()}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Refresh Button */}
      <div className="refresh-section">
        <button className="refresh-btn" onClick={fetchStatistics}>
          🔄 Refresh Data
        </button>
      </div>
    </div>
  );
};

export default Dashboard;
